 855→fn audio_format(audio: &AudioMessageEventContent) -> &'static str {
 856→    audio_format_from_metadata(
 857→        audio
 858→            .info
 859→            .as_ref()
 860→            .and_then(|info| info.mimetype.as_deref()),
 861→        audio
 862→            .filename
