341→/// Handle an OTP verification reply (sender sent a 6-digit code).
342→#[allow(clippy::too_many_arguments)]
343→async fn handle_otp_verification(
344→    otp: &SharedOtp,
345→    client: &Client,
346→    keys: &Keys,
347→    sender_pubkey: &PublicKey,
348→    account_id: &str,
349→    sender_hex: &str,
350→    sender_npub: &str,
351→    code: &str,
